MAP
  NAME "asterra-mapserver"
  STATUS ON
  SIZE 800 600
  EXTENT -180 -90 180 90
  UNITS DD

  WEB
    METADATA
      "wms_title"           "Asterra MapServer"
      "wms_onlineresource"  "http://localhost:8081/"
      "wms_srs"             "EPSG:4326 EPSG:3857"
      "wms_enable_request"  "*"
    END
  END

  PROJECTION
    "init=epsg:4326"
  END

  LAYER
    NAME "geojson_layer"
    STATUS ON
    TYPE POLYGON
    DATA "/data/sample.geojson"

    PROJECTION
      "init=epsg:4326"
    END

    CLASS
      NAME "GeoJSON Features"
      STYLE
        COLOR 100 150 200
        OUTLINECOLOR 0 0 0
        WIDTH 1
      END
    END
  END
END
